 31→// QueryJobs retrieves jobs from the database with optional filtering, pagination,
 32→// and sorting. Security controls are automatically applied based on the user context.
 33→//
 34→// Parameters:
 35→//   - ctx: Context containing user authentication information
 36→//   - filters: Optional job filters (cluster, state, user, time ranges, etc.)
 37→//   - page: Optional pagination parameters (page number and items per page)
 38→//   - order: Optional sorting specification (column or footprint field)
 39→//
 40→// Returns a slice of jobs matching the criteria, or an error if the query fails.
 41→// The function enforces role-based access control through SecurityCheck.
 42→func (r *JobRepository) QueryJobs(
 43→	ctx context.Context,
 44→	filters []*model.JobFilter,
 45→	page *model.PageRequest,
 46→	order *model.OrderByInput,
 47→) ([]*schema.Job, error) {
 48→	query, qerr := SecurityCheck(ctx, sq.Select(jobColumns...).From("job"))
 49→	if qerr != nil {
 50→		return nil, qerr
 51→	}
 52→
 53→	if order != nil {
 54→		field := toSnakeCase(order.Field)
 55→		if order.Type == "col" {
 56→			switch order.Order {
 57→			case model.SortDirectionEnumAsc:
 58→				query = query.OrderBy(fmt.Sprintf("job.%s ASC", field))
 59→			case model.SortDirectionEnumDesc:
 60→				query = query.OrderBy(fmt.Sprintf("job.%s DESC", field))
 61→			default:
 62→				return nil, errors.New("invalid sorting order for column")
 63→			}
 64→		} else {
 65→			// Order by footprint JSON field values
 66→			query = query.Where("JSON_VALID(footprint)")
 67→			switch order.Order {
 68→			case model.SortDirectionEnumAsc:
 69→				query = query.OrderBy(fmt.Sprintf("JSON_EXTRACT(footprint, \"$.%s\") ASC", field))
 70→			case model.SortDirectionEnumDesc:
 71→				query = query.OrderBy(fmt.Sprintf("JSON_EXTRACT(footprint, \"$.%s\") DESC", field))
 72→			default:
 73→				return nil, errors.New("invalid sorting order for footprint")
 74→			}
 75→		}
 76→	}
 77→
 78→	if page != nil && page.ItemsPerPage != -1 {
 79→		limit := uint64(page.ItemsPerPage)
 80→		query = query.Offset((uint64(page.Page) - 1) * limit).Limit(limit)
 81→	}
 82→
 83→	for _, f := range filters {
 84→		query = BuildWhereClause(f, query)
 85→	}
 86→
 87→	rows, err := query.RunWith(r.stmtCache).Query()
 88→	if err != nil {
 89→		queryString, queryVars, _ := query.ToSql()
 90→		return nil, fmt.Errorf("query failed [%s] %v: %w", queryString, queryVars, err)
 91→	}
 92→	defer rows.Close()
 93→
 94→	jobs := make([]*schema.Job, 0, defaultJobsCapacity)
 95→	for rows.Next() {
 96→		job, err := scanJob(rows)
 97→		if err != nil {
 98→			cclog.Warnf("Error scanning job row: %v", err)
 99→			return nil, fmt.Errorf("failed to scan job row: %w", err)
100→		}
101→		jobs = append(jobs, job)
102→	}
103→
104→	if err := rows.Err(); err != nil {
105→		return nil, fmt.Errorf("error iterating job rows: %w", err)
106→	}
107→
108→	return jobs, nil
109→}
