171→// SecurityCheck extracts the user from the context and applies role-based access
172→// control filters to the query. This is a convenience wrapper around SecurityCheckWithUser.
173→func SecurityCheck(ctx context.Context, query sq.SelectBuilder) (sq.SelectBuilder, error) {
174→	user := GetUserFromContext(ctx)
175→	return SecurityCheckWithUser(user, query)
176→}
177→
178→// BuildWhereClause constructs SQL WHERE conditions from a JobFilter and applies
179→// them to the query. Supports filtering by job properties (cluster, state, user),
180→// time ranges, resource usage, tags, and JSON field searches in meta_data,
181→// footprint, and resources columns.
182→func BuildWhereClause(filter *model.JobFilter, query sq.SelectBuilder) sq.SelectBuilder {
183→	// Primary Key
184→	if filter.DbID != nil {
185→		dbIDs := make([]string, len(filter.DbID))
186→		copy(dbIDs, filter.DbID)
187→		query = query.Where(sq.Eq{"job.id": dbIDs})
188→	}
189→	// Explicit indices
190→	if filter.Cluster != nil {
191→		query = buildStringCondition("job.cluster", filter.Cluster, query)
192→	}
193→	if filter.SubCluster != nil {
194→		query = buildStringCondition("job.subcluster", filter.SubCluster, query)
195→	}
196→	if filter.Partition != nil {
197→		query = buildStringCondition("job.cluster_partition", filter.Partition, query)
198→	}
199→	if filter.State != nil {
200→		states := make([]string, len(filter.State))
201→		for i, val := range filter.State {
202→			states[i] = string(val)
203→		}
204→		query = query.Where(sq.Eq{"job.job_state": states})
205→	}
206→	if filter.Shared != nil {
207→		query = query.Where("job.shared = ?", *filter.Shared)
208→	}
209→	if filter.Project != nil {
210→		query = buildStringCondition("job.project", filter.Project, query)
211→	}
212→	if filter.User != nil {
213→		query = buildStringCondition("job.hpc_user", filter.User, query)
214→	}
215→	if filter.NumNodes != nil {
216→		query = buildIntCondition("job.num_nodes", filter.NumNodes, query)
217→	}
218→	if filter.NumAccelerators != nil {
219→		query = buildIntCondition("job.num_acc", filter.NumAccelerators, query)
220→	}
221→	if filter.NumHWThreads != nil {
222→		query = buildIntCondition("job.num_hwthreads", filter.NumHWThreads, query)
223→	}
224→	if filter.ArrayJobID != nil {
225→		query = query.Where("job.array_job_id = ?", *filter.ArrayJobID)
226→	}
227→	if filter.StartTime != nil {
228→		query = buildTimeCondition("job.start_time", filter.StartTime, query)
229→	}
230→	if filter.Duration != nil {
231→		query = buildIntCondition("job.duration", filter.Duration, query)
232→	}
233→	if filter.Energy != nil {
234→		query = buildFloatCondition("job.energy", filter.Energy, query)
235→	}
236→	// Indices on Tag Table
237→	if filter.Tags != nil {
238→		// This is an OR-Logic query: Returns all distinct jobs with at least one of the requested tags; TODO: AND-Logic query?
239→		query = query.Join("jobtag ON jobtag.job_id = job.id").Where(sq.Eq{"jobtag.tag_id": filter.Tags}).Distinct()
240→	}
241→	// No explicit Indices
242→	if filter.JobID != nil {
243→		query = buildStringCondition("job.job_id", filter.JobID, query)
244→	}
245→	// Queries Within JSONs
246→	if filter.MetricStats != nil {
247→		for _, ms := range filter.MetricStats {
248→			query = buildFloatJSONCondition(ms.MetricName, ms.Range, query)
249→		}
250→	}
251→	if filter.Node != nil {
252→		query = buildResourceJSONCondition("hostname", filter.Node, query)
253→	}
254→	if filter.JobName != nil {
255→		query = buildMetaJSONCondition("jobName", filter.JobName, query)
256→	}
257→	if filter.Schedule != nil {
258→		interactiveJobname := "interactive"
259→		switch *filter.Schedule {
260→		case "interactive":
261→			iFilter := model.StringInput{Eq: &interactiveJobname}
262→			query = buildMetaJSONCondition("jobName", &iFilter, query)
263→		case "batch":
264→			sFilter := model.StringInput{Neq: &interactiveJobname}
265→			query = buildMetaJSONCondition("jobName", &sFilter, query)
266→		}
267→	}
268→
269→	// Configurable Filter to exclude recently started jobs, see config.go: ShortRunningJobsDuration
270→	if filter.MinRunningFor != nil {
271→		now := time.Now().Unix()
272→		// Only jobs whose start timestamp is more than MinRunningFor seconds in the past
273→		// If a job completed within the configured timeframe, it will still show up after the start_time matches the condition!
274→		query = query.Where(sq.Lt{"job.start_time": (now - int64(*filter.MinRunningFor))})
275→	}
276→	return query
277→}
278→
279→// buildIntCondition creates clauses for integer range filters, using BETWEEN only if required.
280→func buildIntCondition(field string, cond *config.IntRange, query sq.SelectBuilder) sq.SelectBuilder {
281→	if cond.From != 1 && cond.To != 0 {
282→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
283→	} else if cond.From != 1 && cond.To == 0 {
284→		return query.Where(field+" >= ?", cond.From)
285→	} else if cond.From == 1 && cond.To != 0 {
286→		return query.Where(field+" <= ?", cond.To)
287→	} else {
288→		return query
289→	}
290→}
291→
292→// buildFloatCondition creates a clauses for float range filters, using BETWEEN only if required.
293→func buildFloatCondition(field string, cond *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
294→	if cond.From != 1.0 && cond.To != 0.0 {
295→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
296→	} else if cond.From != 1.0 && cond.To == 0.0 {
297→		return query.Where(field+" >= ?", cond.From)
298→	} else if cond.From == 1.0 && cond.To != 0.0 {
299→		return query.Where(field+" <= ?", cond.To)
300→	} else {
301→		return query
302→	}
303→}
304→
305→// buildTimeCondition creates time range filters supporting absolute timestamps,
306→// relative time ranges (last6h, last24h, last7d, last30d), or open-ended ranges.
307→// Reminder: BETWEEN Queries are slower and dont use indices as frequently: Only use if both conditions required
308→func buildTimeCondition(field string, cond *config.TimeRange, query sq.SelectBuilder) sq.SelectBuilder {
309→	if cond.From != nil && cond.To != nil {
310→		return query.Where(field+" BETWEEN ? AND ?", cond.From.Unix(), cond.To.Unix())
311→	} else if cond.From != nil {
312→		return query.Where(field+" >= ?", cond.From.Unix())
313→	} else if cond.To != nil {
314→		return query.Where(field+" <= ?", cond.To.Unix())
315→	} else if cond.Range != "" {
316→		now := time.Now().Unix()
317→		var then int64
318→		switch cond.Range {
319→		case "last6h":
320→			then = now - (60 * 60 * 6)
321→		case "last24h":
322→			then = now - (60 * 60 * 24)
323→		case "last7d":
324→			then = now - (60 * 60 * 24 * 7)
325→		case "last30d":
326→			then = now - (60 * 60 * 24 * 30)
327→		default:
328→			cclog.Debugf("No known named timeRange: startTime.range = %s", cond.Range)
329→			return query
330→		}
331→		return query.Where(field+" >= ?", then)
332→	} else {
333→		return query
334→	}
335→}
336→
337→// buildFloatJSONCondition creates a filter on a numeric field within the footprint JSON column, using BETWEEN only if required.
338→func buildFloatJSONCondition(jsonField string, cond *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
339→	query = query.Where("JSON_VALID(footprint)")
340→	if cond.From != 1.0 && cond.To != 0.0 {
341→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") BETWEEN ? AND ?", cond.From, cond.To)
342→	} else if cond.From != 1.0 && cond.To == 0.0 {
343→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") >= ?", cond.From)
344→	} else if cond.From == 1.0 && cond.To != 0.0 {
345→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") <= ?", cond.To)
346→	} else {
347→		return query
348→	}
349→}
350→
351→// buildStringCondition creates filters for string fields supporting equality,
352→// inequality, prefix, suffix, substring, and IN list matching.
353→func buildStringCondition(field string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
354→	if cond.Eq != nil {
355→		return query.Where(field+" = ?", *cond.Eq)
356→	}
357→	if cond.Neq != nil {
358→		return query.Where(field+" != ?", *cond.Neq)
359→	}
360→	if cond.StartsWith != nil {
361→		return query.Where(field+" LIKE ?", fmt.Sprint(*cond.StartsWith, "%"))
362→	}
363→	if cond.EndsWith != nil {
364→		return query.Where(field+" LIKE ?", fmt.Sprint("%", *cond.EndsWith))
365→	}
366→	if cond.Contains != nil {
367→		return query.Where(field+" LIKE ?", fmt.Sprint("%", *cond.Contains, "%"))
368→	}
369→	if cond.In != nil {
370→		queryElements := make([]string, len(cond.In))
371→		copy(queryElements, cond.In)
372→		return query.Where(sq.Or{sq.Eq{field: queryElements}})
373→	}
374→	return query
375→}
376→
377→// buildMetaJSONCondition creates filters on fields within the meta_data JSON column.
378→func buildMetaJSONCondition(jsonField string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
379→	query = query.Where("JSON_VALID(meta_data)")
380→	if cond.Eq != nil {
381→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") = ?", *cond.Eq)
382→	}
383→	if cond.Neq != nil {
384→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") != ?", *cond.Neq)
385→	}
386→	if cond.StartsWith != nil {
387→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint(*cond.StartsWith, "%"))
388→	}
389→	if cond.EndsWith != nil {
390→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint("%", *cond.EndsWith))
391→	}
392→	if cond.Contains != nil {
393→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint("%", *cond.Contains, "%"))
394→	}
395→	return query
396→}
397→
398→// buildResourceJSONCondition creates filters on fields within the resources JSON array column.
399→// Uses json_each to search within array elements.
400→func buildResourceJSONCondition(jsonField string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
401→	query = query.Where("JSON_VALID(resources)")
402→	if cond.Eq != nil {
403→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") = ?)", *cond.Eq)
404→	}
405→	if cond.Neq != nil { // Currently Unused
406→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") != ?)", *cond.Neq)
407→	}
408→	if cond.StartsWith != nil { // Currently Unused
409→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\")) LIKE ?)", fmt.Sprint(*cond.StartsWith, "%"))
410→	}
411→	if cond.EndsWith != nil { // Currently Unused
412→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") LIKE ?)", fmt.Sprint("%", *cond.EndsWith))
413→	}
414→	if cond.Contains != nil {
415→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") LIKE ?)", fmt.Sprint("%", *cond.Contains, "%"))
416→	}
417→	return query
418→}
419→
420→var (
421→	matchFirstCap = regexp.MustCompile("(.)([A-Z][a-z]+)")
422→	matchAllCap   = regexp.MustCompile("([a-z0-9])([A-Z])")
423→)
424→
425→// toSnakeCase converts camelCase strings to snake_case for SQL column names.
426→// Includes security checks to prevent SQL injection attempts.
427→// Panics if potentially dangerous characters are detected.
428→func toSnakeCase(str string) string {
429→	for _, c := range str {
430→		if c == '\'' || c == '\\' || c == '"' || c == ';' || c == '-' || c == ' ' {
431→			cclog.Panicf("toSnakeCase: potentially dangerous character detected in input: %q", str)
432→		}
433→	}
434→
435→	snake := matchFirstCap.ReplaceAllString(str, "${1}_${2}")
436→	snake = matchAllCap.ReplaceAllString(snake, "${1}_${2}")
437→	return strings.ToLower(snake)
438→}
