136→// SecurityCheckWithUser applies role-based access control filters to a job query
137→// based on the provided user's roles and permissions.
138→//
139→// Access rules by role:
140→//   - API role (exclusive): Full access to all jobs
141→//   - Admin/Support roles: Full access to all jobs
142→//   - Manager role: Access to jobs in managed projects plus own jobs
143→//   - User role: Access only to own jobs
144→//
145→// Returns an error if the user is nil or has no recognized roles.
146→func SecurityCheckWithUser(user *schema.User, query sq.SelectBuilder) (sq.SelectBuilder, error) {
147→	if user == nil {
148→		var qnil sq.SelectBuilder
149→		return qnil, fmt.Errorf("user context is nil")
150→	}
151→
152→	switch {
153→	case len(user.Roles) == 1 && user.HasRole(schema.RoleAPI):
154→		return query, nil
155→	case user.HasAnyRole([]schema.Role{schema.RoleAdmin, schema.RoleSupport}):
156→		return query, nil
157→	case user.HasRole(schema.RoleManager):
158→		if len(user.Projects) != 0 {
159→			return query.Where(sq.Or{sq.Eq{"job.project": user.Projects}, sq.Eq{"job.hpc_user": user.Username}}), nil
160→		}
161→		cclog.Debugf("Manager '%s' has no assigned projects, restricting to personal jobs", user.Username)
162→		return query.Where("job.hpc_user = ?", user.Username), nil
163→	case user.HasRole(schema.RoleUser):
164→		return query.Where("job.hpc_user = ?", user.Username), nil
165→	default:
166→		var qnil sq.SelectBuilder
167→		return qnil, fmt.Errorf("user has no or unknown roles")
168→	}
169→}
