119→// AddUser creates a new user in the database.
120→// Passwords are automatically hashed with bcrypt before storage.
121→// Auth source determines authentication method (local, LDAP, etc.).
122→//
123→// Required fields: Username, Roles
124→// Optional fields: Name, Email, Password, Projects, AuthSource
125→func (r *UserRepository) AddUser(user *schema.User) error {
126→	rolesJson, _ := json.Marshal(user.Roles)
127→	projectsJson, _ := json.Marshal(user.Projects)
128→
129→	cols := []string{"username", "roles", "projects"}
130→	vals := []any{user.Username, string(rolesJson), string(projectsJson)}
131→
132→	if user.Name != "" {
133→		cols = append(cols, "name")
134→		vals = append(vals, user.Name)
135→	}
136→	if user.Email != "" {
137→		cols = append(cols, "email")
138→		vals = append(vals, user.Email)
139→	}
140→	if user.Password != "" {
141→		password, err := bcrypt.GenerateFromPassword([]byte(user.Password), bcrypt.DefaultCost)
142→		if err != nil {
143→			cclog.Error("Error while encrypting new user password")
144→			return err
145→		}
146→		cols = append(cols, "password")
147→		vals = append(vals, string(password))
148→	}
149→	if user.AuthSource != -1 {
150→		cols = append(cols, "ldap")
151→		vals = append(vals, int(user.AuthSource))
152→	}
153→
154→	if _, err := sq.Insert("hpc_user").Columns(cols...).Values(vals...).RunWith(r.DB).Exec(); err != nil {
155→		cclog.Errorf("Error while inserting new user '%v' into DB", user.Username)
156→		return err
157→	}
158→
159→	cclog.Infof("new user %#v created (roles: %s, auth-source: %d, projects: %s)", user.Username, rolesJson, user.AuthSource, projectsJson)
160→
161→	// DEPRECATED: SUPERSEDED BY NEW USER CONFIG - userConfig.go / web.go
162→	defaultMetricsCfg, err := config.LoadDefaultMetricsConfig()
163→	if err != nil {
164→		cclog.Errorf("Error loading default metrics config: %v", err)
165→	} else if defaultMetricsCfg != nil {
166→		for _, cluster := range defaultMetricsCfg.Clusters {
167→			metricsArray := config.ParseMetricsString(cluster.DefaultMetrics)
168→			metricsJSON, err := json.Marshal(metricsArray)
169→			if err != nil {
170→				cclog.Errorf("Error marshaling default metrics for cluster %s: %v", cluster.Name, err)
171→				continue
172→			}
173→			// Note: StatisticsTable now has different key (metricConfig_jobViewTableMetrics): Not updated here.
174→			confKey := "metricConfig_jobViewPlotMetrics:" + cluster.Name
175→			if _, err := sq.Insert("configuration").
176→				Columns("username", "confkey", "value").
177→				Values(user.Username, confKey, string(metricsJSON)).
178→				RunWith(r.DB).Exec(); err != nil {
179→				cclog.Errorf("Error inserting default job view metrics for user %s and cluster %s: %v", user.Username, cluster.Name, err)
180→			} else {
181→				cclog.Infof("Default job view metrics for user %s and cluster %s set to %s", user.Username, cluster.Name, string(metricsJSON))
182→			}
183→		}
184→	}
185→	// END DEPRECATION
186→
187→	return nil
188→}
