287→		rawroles := ""
288→		rawprojects := ""
289→		user := &schema.User{}
290→		var name, email sql.NullString
291→		if err := rows.Scan(&user.Username, &name, &email, &rawroles, &rawprojects); err != nil {
292→			cclog.Warn("Error while scanning user list")
