476→func (r *UserRepository) FetchUserInCtx(ctx context.Context, username string) (*model.User, error) {
477→	me := GetUserFromContext(ctx)
478→	if me != nil && me.Username != username &&
479→		me.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleSupport, schema.RoleManager}) {
480→		return nil, errors.New("forbidden")
481→	}
482→
483→	user := &model.User{Username: username}
484→	var name, email sql.NullString
485→	if err := sq.Select("name", "email").From("hpc_user").Where("hpc_user.username = ?", username).
486→		RunWith(r.DB).QueryRow().Scan(&name, &email); err != nil {
487→		if err == sql.ErrNoRows {
488→			/* This warning will be logged *often* for non-local users, i.e. users mentioned only in job-table or archive, */
489→			/* since FetchUser will be called to retrieve full name and mail for every job in query/list									 */
490→			// cclog.Warnf("User '%s' Not found in DB", username)
491→			return nil, nil
492→		}
493→
494→		cclog.Warnf("Error while fetching user '%s'", username)
495→		return nil, err
496→	}
497→
498→	user.Name = name.String
499→	user.Email = email.String
500→	return user, nil
501→}
