337→// buildFloatJSONCondition creates a filter on a numeric field within the footprint JSON column, using BETWEEN only if required.
338→func buildFloatJSONCondition(jsonField string, cond *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
339→	query = query.Where("JSON_VALID(footprint)")
340→	if cond.From != 1.0 && cond.To != 0.0 {
341→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") BETWEEN ? AND ?", cond.From, cond.To)
342→	} else if cond.From != 1.0 && cond.To == 0.0 {
343→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") >= ?", cond.From)
344→	} else if cond.From == 1.0 && cond.To != 0.0 {
345→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") <= ?", cond.To)
346→	} else {
347→		return query
348→	}
349→}
