272→func (r *UserRepository) ListUsers(specialsOnly bool) ([]*schema.User, error) {
273→	q := sq.Select("username", "name", "email", "roles", "projects").From("hpc_user")
274→	if specialsOnly {
275→		q = q.Where("(roles != '[\"user\"]' AND roles != '[]')")
276→	}
277→
278→	rows, err := q.RunWith(r.DB).Query()
279→	if err != nil {
280→		cclog.Warn("Error while querying user list")
281→		return nil, err
282→	}
283→
284→	users := make([]*schema.User, 0)
285→	defer rows.Close()
286→	for rows.Next() {
287→		rawroles := ""
288→		rawprojects := ""
289→		user := &schema.User{}
290→		var name, email sql.NullString
291→		if err := rows.Scan(&user.Username, &name, &email, &rawroles, &rawprojects); err != nil {
292→			cclog.Warn("Error while scanning user list")
293→			return nil, err
294→		}
295→
296→		if err := json.Unmarshal([]byte(rawroles), &user.Roles); err != nil {
297→			cclog.Warn("Error while unmarshaling raw role list")
298→			return nil, err
299→		}
300→
301→		if err := json.Unmarshal([]byte(rawprojects), &user.Projects); err != nil {
302→			return nil, err
303→		}
304→
305→		user.Name = name.String
306→		user.Email = email.String
307→		users = append(users, user)
308→	}
309→	return users, nil
310→}
