312→// AddRole adds a role to a user's role list.
313→// Role string is automatically lowercased.
314→// Valid roles: admin, support, manager, api, user
315→//
316→// Returns error if:
317→//   - User doesn't exist
318→//   - Role is invalid
319→//   - User already has the role
320→func (r *UserRepository) AddRole(
321→	ctx context.Context,
322→	username string,
323→	queryrole string,
324→) error {
325→	newRole := strings.ToLower(queryrole)
326→	user, err := r.GetUser(username)
327→	if err != nil {
328→		cclog.Warnf("Could not load user '%s'", username)
329→		return err
330→	}
331→
332→	exists, valid := user.HasValidRole(newRole)
333→
334→	if !valid {
335→		return fmt.Errorf("supplied role is no valid option : %v", newRole)
336→	}
337→	if exists {
338→		return fmt.Errorf("user %v already has role %v", username, newRole)
339→	}
340→
341→	roles, _ := json.Marshal(append(user.Roles, newRole))
342→	if _, err := sq.Update("hpc_user").Set("roles", roles).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
343→		cclog.Errorf("error while adding new role for user '%s'", user.Username)
344→		return err
345→	}
346→	return nil
347→}
348→
349→// RemoveRole removes a role from a user's role list.
350→//
351→// Special rules:
352→//   - Cannot remove "manager" role while user has assigned projects
353→//   - Must remove all projects first before removing manager role
354→func (r *UserRepository) RemoveRole(ctx context.Context, username string, queryrole string) error {
355→	oldRole := strings.ToLower(queryrole)
356→	user, err := r.GetUser(username)
357→	if err != nil {
358→		cclog.Warnf("Could not load user '%s'", username)
359→		return err
360→	}
361→
362→	exists, valid := user.HasValidRole(oldRole)
363→
364→	if !valid {
365→		return fmt.Errorf("supplied role is no valid option : %v", oldRole)
366→	}
367→	if !exists {
368→		return fmt.Errorf("role already deleted for user '%v': %v", username, oldRole)
369→	}
370→
371→	if oldRole == schema.GetRoleString(schema.RoleManager) && len(user.Projects) != 0 {
372→		return fmt.Errorf("cannot remove role 'manager' while user %s still has assigned project(s) : %v", username, user.Projects)
373→	}
374→
375→	var newroles []string
376→	for _, r := range user.Roles {
377→		if r != oldRole {
378→			newroles = append(newroles, r) // Append all roles not matching requested to be deleted role
379→		}
380→	}
381→
382→	mroles, _ := json.Marshal(newroles)
383→	if _, err := sq.Update("hpc_user").Set("roles", mroles).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
384→		cclog.Errorf("Error while removing role for user '%s'", user.Username)
385→		return err
386→	}
387→	return nil
388→}
389→
390→// AddProject assigns a project to a manager user.
391→// Only users with the "manager" role can have assigned projects.
392→//
393→// Returns error if:
394→//   - User doesn't have manager role
395→//   - User already manages the project
396→func (r *UserRepository) AddProject(
397→	ctx context.Context,
398→	username string,
399→	project string,
400→) error {
401→	user, err := r.GetUser(username)
402→	if err != nil {
403→		return err
404→	}
405→
406→	if !user.HasRole(schema.RoleManager) {
407→		return fmt.Errorf("user '%s' is not a manager", username)
408→	}
409→
410→	if user.HasProject(project) {
411→		return fmt.Errorf("user '%s' already manages project '%s'", username, project)
412→	}
413→
414→	projects, _ := json.Marshal(append(user.Projects, project))
415→	if _, err := sq.Update("hpc_user").Set("projects", projects).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
416→		return err
417→	}
418→
419→	return nil
420→}
421→
422→func (r *UserRepository) RemoveProject(ctx context.Context, username string, project string) error {
423→	user, err := r.GetUser(username)
424→	if err != nil {
425→		return err
426→	}
427→
428→	if !user.HasRole(schema.RoleManager) {
429→		return fmt.Errorf("user '%#v' is not a manager", username)
430→	}
431→
432→	if !user.HasProject(project) {
433→		return fmt.Errorf("user '%#v': Cannot remove project '%#v' - Does not match", username, project)
434→	}
435→
436→	var exists bool
437→	var newprojects []string
438→	for _, p := range user.Projects {
439→		if p != project {
440→			newprojects = append(newprojects, p) // Append all projects not matching requested to be deleted project
441→		} else {
442→			exists = true
443→		}
444→	}
445→
446→	if exists {
447→		var result any
448→		if len(newprojects) == 0 {
449→			result = "[]"
450→		} else {
451→			result, _ = json.Marshal(newprojects)
452→		}
453→		if _, err := sq.Update("hpc_user").Set("projects", result).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
454→			return err
455→		}
456→		return nil
457→	} else {
458→		return fmt.Errorf("user %s already does not manage project %s", username, project)
459→	}
460→}
