  6→// Package repository provides job query functionality with filtering, pagination,
  7→// and security controls. This file contains the main query builders and security
  8→// checks for job retrieval operations.
  9→package repository
 10→
 11→import (
 12→	"context"
 13→	"errors"
 14→	"fmt"
 15→	"regexp"
 16→	"strings"
 17→	"time"
 18→
 19→	"github.com/ClusterCockpit/cc-backend/internal/config"
 20→	"github.com/ClusterCockpit/cc-backend/internal/graph/model"
 21→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 22→	"github.com/ClusterCockpit/cc-lib/v2/schema"
 23→	sq "github.com/Masterminds/squirrel"
 24→)
