178→// BuildWhereClause constructs SQL WHERE conditions from a JobFilter and applies
179→// them to the query. Supports filtering by job properties (cluster, state, user),
180→// time ranges, resource usage, tags, and JSON field searches in meta_data,
181→// footprint, and resources columns.
182→func BuildWhereClause(filter *model.JobFilter, query sq.SelectBuilder) sq.SelectBuilder {
183→	// Primary Key
184→	if filter.DbID != nil {
185→		dbIDs := make([]string, len(filter.DbID))
186→		copy(dbIDs, filter.DbID)
187→		query = query.Where(sq.Eq{"job.id": dbIDs})
188→	}
189→	// Explicit indices
190→	if filter.Cluster != nil {
191→		query = buildStringCondition("job.cluster", filter.Cluster, query)
192→	}
193→	if filter.SubCluster != nil {
194→		query = buildStringCondition("job.subcluster", filter.SubCluster, query)
195→	}
196→	if filter.Partition != nil {
197→		query = buildStringCondition("job.cluster_partition", filter.Partition, query)
198→	}
199→	if filter.State != nil {
200→		states := make([]string, len(filter.State))
201→		for i, val := range filter.State {
202→			states[i] = string(val)
203→		}
204→		query = query.Where(sq.Eq{"job.job_state": states})
205→	}
206→	if filter.Shared != nil {
207→		query = query.Where("job.shared = ?", *filter.Shared)
208→	}
209→	if filter.Project != nil {
210→		query = buildStringCondition("job.project", filter.Project, query)
211→	}
212→	if filter.User != nil {
213→		query = buildStringCondition("job.hpc_user", filter.User, query)
214→	}
215→	if filter.NumNodes != nil {
216→		query = buildIntCondition("job.num_nodes", filter.NumNodes, query)
217→	}
218→	if filter.NumAccelerators != nil {
219→		query = buildIntCondition("job.num_acc", filter.NumAccelerators, query)
220→	}
221→	if filter.NumHWThreads != nil {
222→		query = buildIntCondition("job.num_hwthreads", filter.NumHWThreads, query)
223→	}
224→	if filter.ArrayJobID != nil {
225→		query = query.Where("job.array_job_id = ?", *filter.ArrayJobID)
226→	}
227→	if filter.StartTime != nil {
228→		query = buildTimeCondition("job.start_time", filter.StartTime, query)
229→	}
230→	if filter.Duration != nil {
231→		query = buildIntCondition("job.duration", filter.Duration, query)
232→	}
233→	if filter.Energy != nil {
234→		query = buildFloatCondition("job.energy", filter.Energy, query)
235→	}
236→	// Indices on Tag Table
237→	if filter.Tags != nil {
238→		// This is an OR-Logic query: Returns all distinct jobs with at least one of the requested tags; TODO: AND-Logic query?
239→		query = query.Join("jobtag ON jobtag.job_id = job.id").Where(sq.Eq{"jobtag.tag_id": filter.Tags}).Distinct()
240→	}
241→	// No explicit Indices
242→	if filter.JobID != nil {
243→		query = buildStringCondition("job.job_id", filter.JobID, query)
244→	}
245→	// Queries Within JSONs
246→	if filter.MetricStats != nil {
247→		for _, ms := range filter.MetricStats {
248→			query = buildFloatJSONCondition(ms.MetricName, ms.Range, query)
249→		}
250→	}
251→	if filter.Node != nil {
252→		query = buildResourceJSONCondition("hostname", filter.Node, query)
253→	}
254→	if filter.JobName != nil {
255→		query = buildMetaJSONCondition("jobName", filter.JobName, query)
256→	}
257→	if filter.Schedule != nil {
258→		interactiveJobname := "interactive"
259→		switch *filter.Schedule {
260→		case "interactive":
261→			iFilter := model.StringInput{Eq: &interactiveJobname}
262→			query = buildMetaJSONCondition("jobName", &iFilter, query)
263→		case "batch":
264→			sFilter := model.StringInput{Neq: &interactiveJobname}
265→			query = buildMetaJSONCondition("jobName", &sFilter, query)
266→		}
267→	}
268→
269→	// Configurable Filter to exclude recently started jobs, see config.go: ShortRunningJobsDuration
270→	if filter.MinRunningFor != nil {
271→		now := time.Now().Unix()
272→		// Only jobs whose start timestamp is more than MinRunningFor seconds in the past
273→		// If a job completed within the configured timeframe, it will still show up after the start_time matches the condition!
274→		query = query.Where(sq.Lt{"job.start_time": (now - int64(*filter.MinRunningFor))})
275→	}
276→	return query
277→}
