-- Pattern 1: Default job list (multi-state + ORDER BY start_time DESC)
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.job_state IN ('completed', 'running', 'failed') ORDER BY job.start_time DESC LIMIT 50 OFFSET 0;
" && echo '===P2===' && sqlite3 ./var/job.db "
-- Pattern 2: Cluster + state + ORDER BY start_time
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.cluster = 'fritz' AND job.job_state IN ('completed','running') ORDER BY job.start_time DESC LIMIT 50;
" && echo '===P3===' && sqlite3 ./var/job.db "
-- Pattern 3: User filter + ORDER BY start_time
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.hpc_user = 'alice' ORDER BY job.start_time DESC LIMIT 50;
" && echo '===P4===' && sqlite3 ./var/job.db "
-- Pattern 4: Stats aggregation with cluster + state
EXPLAIN QUERY PLAN SELECT COUNT(job.id), SUM(job.duration) FROM job WHERE job.cluster = 'fritz' AND job.job_state = 'completed';
" && echo '===P5===' && sqlite3 ./var/job.db "
-- Pattern 5: Find by job_id + cluster + start_time (unique lookup)
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.job_id = 123 AND job.cluster = 'fritz' AND job.start_time = 1000 ORDER BY job.id DESC LIMIT 1;
" && echo '===P6===' && sqlite3 ./var/job.db "
-- Pattern 6: Running jobs for cluster
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.cluster = 'fritz' AND job.job_state = 'running' AND job.duration > 300;
" && echo '===P7===' && sqlite3 ./var/job.db "
-- Pattern 7: Time range query
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.start_time BETWEEN 1700000000 AND 1710000000 ORDER BY job.cluster, job.subcluster, job.project, job.start_time;
" && echo '===P8===' && sqlite3 ./var/job.db "
-- Pattern 8: GroupBy user with cluster filter
EXPLAIN QUERY PLAN SELECT job.hpc_user, COUNT(job.id) FROM job WHERE job.cluster = 'fritz' GROUP BY job.hpc_user;
" && echo '===P9===' && sqlite3 ./var/job.db "
-- Pattern 9: Concurrent jobs (overlap detection)
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.cluster = 'fritz' AND job.job_state != 'running' AND job.start_time <= 1710000000 AND (job.start_time + job.duration) > 1700000000;
"

sqlite3 ./var/job.db "
-- Pattern 10: Project filter + state + ORDER BY start_time (manager view)
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.project IN ('proj1','proj2','proj3') AND job.job_state IN ('completed','running') ORDER BY job.start_time DESC LIMIT 50;
" && echo '===P11===' && sqlite3 ./var/job.db "
-- Pattern 11: User security check (user role) + state + sort
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.hpc_user = 'alice' AND job.job_state IN ('completed','running','failed') ORDER BY job.start_time DESC LIMIT 50;
" && echo '===P12===' && sqlite3 ./var/job.db "
-- Pattern 12: Cluster + state + sort by duration
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.cluster = 'fritz' AND job.job_state = 'completed' ORDER BY job.duration DESC LIMIT 50;
" && echo '===P13===' && sqlite3 ./var/job.db "
-- Pattern 13: Cluster + state + sort by num_nodes
EXPLAIN QUERY PLAN SELECT * FROM job WHERE job.cluster = 'fritz' AND job.job_state = 'completed' ORDER BY job.num_nodes DESC LIMIT 50;
" && echo '===P14===' && sqlite3 ./var/job.db "
-- Pattern 14: Tag join query
EXPLAIN QUERY PLAN SELECT DISTINCT job.* FROM job JOIN jobtag ON jobtag.job_id = job.id WHERE jobtag.tag_id = 5 ORDER BY job.start_time DESC LIMIT 50;
" && echo '===P15===' && sqlite3 ./var/job.db "
-- Pattern 15: Delete jobs before timestamp
EXPLAIN QUERY PLAN SELECT job.id FROM job WHERE job.start_time < 1700000000;
" && echo '===P16===' && sqlite3 ./var/job.db "
-- Pattern 16: Non-running jobs list (GetJobList for archiving)  
EXPLAIN QUERY PLAN SELECT job.id FROM job WHERE job.job_state != 'running' LIMIT 50 OFFSET 0;
"

# Check DB size and index overhead
sqlite3 ./var/job.db "
SELECT 'table_pages', (SELECT page_count FROM pragma_page_count()) as total_pages;
" && sqlite3 ./var/job.db "
