-- #6: Cluster + project
-- Serves: GROUP BY project with cluster filter, cluster+project filter
CREATE INDEX IF NOT EXISTS jobs_cluster_project
    ON job (cluster, project);

-- #7: Cluster + subcluster
-- Serves: GROUP BY subcluster with cluster, cluster+subcluster filter
CREATE INDEX IF NOT EXISTS jobs_cluster_subcluster
    ON job (cluster, subcluster);

-- ============================================================
-- GROUP 3: User-prefixed indexes (security filter for user role)
-- ============================================================

-- #8: User + start_time + duration
-- Serves: User role security filter + default sort, user filter + sort start_time,
--         user + multi-state + sort start_time
-- Query plans: #3, #11
-- Prefix (hpc_user) covers: plain user equality, user role security filter
CREATE INDEX IF NOT EXISTS jobs_user_starttime_duration
    ON job (hpc_user, start_time, duration);

-- ============================================================
-- GROUP 4: Project-prefixed indexes (security filter for manager role)
-- ============================================================

-- #9: Project + start_time + duration
-- Serves: Manager role security filter (project IN) + default sort,
--         project filter + sort start_time
-- Prefix (project) covers: plain project equality
CREATE INDEX IF NOT EXISTS jobs_project_starttime_duration
    ON job (project, start_time, duration);

-- ============================================================
-- GROUP 5: JobState-prefixed indexes
-- ============================================================

-- #10: JobState + project
-- Serves: State filter + project filter (manager security within state query)
-- Query plan: #10
CREATE INDEX IF NOT EXISTS jobs_jobstate_project
    ON job (job_state, project);

-- #11: JobState + duration + start_time
-- Serves: Non-running jobs scan (covering for state+duration+start_time),
--         state filter + sort duration, state filter + sort start_time
-- Query plan: #16 (alternative), GetJobList
CREATE INDEX IF NOT EXISTS jobs_jobstate_duration_starttime
    ON job (job_state, duration, start_time);

-- ============================================================
-- GROUP 6: Rare/occasional filter indexes
-- ============================================================

-- #12: Array job lookup
-- Serves: array_job_id filter (rare but needs index when used)
CREATE INDEX IF NOT EXISTS jobs_arrayjobid
    ON job (array_job_id);

-- ============================================================
-- GROUP 7: Secondary sort indexes (for non-start_time ORDER BY)
-- ============================================================
-- These handle the ~20% of queries that sort by duration, num_nodes,
-- num_hwthreads, num_acc, or energy without a filter prefix that
-- already provides the sort order.

-- #13: Cluster + num_hwthreads (for cluster + sort num_hwthreads)
CREATE INDEX IF NOT EXISTS jobs_cluster_numhwthreads
    ON job (cluster, num_hwthreads);

-- #14: Cluster + num_acc (for cluster + sort num_acc)
CREATE INDEX IF NOT EXISTS jobs_cluster_numacc
    ON job (cluster, num_acc);

-- #15: Cluster + energy (for cluster + sort energy)
CREATE INDEX IF NOT EXISTS jobs_cluster_energy
    ON job (cluster, energy);

-- #16: Cluster + num_nodes (for cluster + sort num_nodes without state filter)
CREATE INDEX IF NOT EXISTS jobs_cluster_numnodes
    ON job (cluster, num_nodes);

-- #17: Cluster + duration + start_time (for cluster + sort duration)
CREATE INDEX IF NOT EXISTS jobs_cluster_duration_starttime
    ON job (cluster, duration, start_time);

-- ============================================================
-- GROUP 8: Covering indexes for specific aggregation patterns
-- ============================================================

-- #18: JobState + hpc_user (for state-filtered user aggregation)
-- Serves: state filter + GROUP BY user, state + user filter
CREATE INDEX IF NOT EXISTS jobs_jobstate_user
    ON job (job_state, hpc_user);

-- ============================================================
-- GROUP 9: jobtag indexes (from migration 10, kept as-is)
-- ============================================================

-- #19-20: Already created in migration 10, listed for completeness
-- These are NOT recreated here since they already exist.
-- CREATE INDEX IF NOT EXISTS tags_jobid ON jobtag (job_id);
-- CREATE INDEX IF NOT EXISTS tags_tagid ON jobtag (tag_id);

-- ============================================================
-- GROUP 10: Partition-specific (optional, only if partition
-- filtering is common in your deployment)
-- ============================================================

-- #21: Cluster + partition + start_time
-- Serves: Cluster+partition filter + default sort
-- Only needed if partition filtering is common; otherwise the
-- cluster_starttime_duration index handles it with a table filter
CREATE INDEX IF NOT EXISTS jobs_cluster_partition_starttime
    ON job (cluster, cluster_partition, start_time);

-- #22: Cluster + job_state + start_time + duration
-- Serves: Cluster+state+sort by start_time (alternative to using
-- cluster_jobstate_duration_starttime when ORDER BY start_time is needed
-- and the planner prefers this column order)
CREATE INDEX IF NOT EXISTS jobs_cluster_jobstate_starttime_duration
    ON job (cluster, job_state, start_time, duration);

-- Update query planner statistics (critical for correct index selection)
PRAGMA optimize;
